function [wHIn,wLIn,wHOut,wLOut,peak] = fGetFwAnyMaxV01(x,cnts,ratio)% Returns width for any-maximum%% [wHIn,wLIn,wHOut,wLOut,peak] = fGetFwAnyMaxV01(x,cnts,ratio)% x: axis information (x axis)% cnts: counts for each point (yaxis)% ratio: for fwhm->0.5, % wHIn: width for high side from peak% wLIn: width for low side from peak% wHOut: width for high side from high side edge% wLOut: width for low side from low side edge% peak: peak%%%%%%%%%%%%%%%%%%%%%%%%%%%%%% Get full width any maximum, ver.1%% Kei Nakamura% Created on Thursday, February 11th 2010.% Modified on %% ver.1: inherited from fGetFwhmV03%%%%%%%%%%%%%%%%%%%%%%%%%%%%% main body% in case 0 length array inputif sum(cnts)==0|numel(x)<=3;    wHIn = 0;    wLIn = 0;    wHOut = 0;    wLOut = 0;    peak = 0;else    % main part    sx = numel(cnts);               % size x    [maxV maxInd] = max(cnts);      % max value and max index for counts    peak = x(maxInd);              % peak for X        % High side    if maxInd==sx;                  % peak at the end edge        wHIn = 0;        wHOut = 0;    else                            % peak is not at edge            % finding half point, high side, from inside        hlfHInd = maxInd;                      % index for half, high side, start from peak        while cnts(hlfHInd)>ratio*maxV&hlfHInd<sx;            hlfHInd = hlfHInd + 1;        end        y1 = cnts(hlfHInd);        x1 = x(hlfHInd);        y2 = cnts(hlfHInd-1);        x2 = x(hlfHInd-1);        d1 = abs(ratio*maxV - y1);        d2 = abs(ratio*maxV - y2);        xHlf = (x1*d2+x2*d1)/(d1+d2);        wHIn = xHlf - peak;        %wHIn = x(hlfHInd)-peak;        %disp([peak xHlf x(hlfHInd)]);        %disp([wHIn2 wHIn]);        % finding half point, high side, from outside        hlfHOInd = sx-1;           % half, high side, outside, index, start from edge from 1        while cnts(hlfHOInd)<ratio*maxV;            hlfHOInd = hlfHOInd - 1;        end        y1 = cnts(hlfHOInd);        x1 = x(hlfHOInd);        y2 = cnts(hlfHOInd+1);        x2 = x(hlfHOInd+1);        d1 = abs(ratio*maxV - y1);        d2 = abs(ratio*maxV - y2);        xHlf = (x1*d2+x2*d1)/(d1+d2);        wHOut = xHlf - peak;        %wHOut = x(hlfHOInd)-peak;        %disp([wHOut2 wHOut]);    end        % Low side    if maxInd==1;                  % peak at the low edge        wLIn = 0;        wLOut = 0;               % no width    else                            % peak is not at edge            % finding half lowside, from inside        hlfLInd = maxInd;           % half, Low side, (Inside), index, start from max        while cnts(hlfLInd)>ratio*maxV&hlfLInd>2;            hlfLInd = hlfLInd - 1;        end        y1 = cnts(hlfLInd);        x1 = x(hlfLInd);        y2 = cnts(hlfLInd+1);        x2 = x(hlfLInd+1);        d1 = abs(ratio*maxV - y1);        d2 = abs(ratio*maxV - y2);        xHlf = (x1*d2+x2*d1)/(d1+d2);        wLIn = peak - xHlf;        %wLIn = peak - x(hlfLInd);        %disp([wLIn2 wLIn]);        % finding half lowside, from outside        hlfLOInd = 2;      % half, lowside, outside, index        while cnts(hlfLOInd)<ratio*maxV;            hlfLOInd = hlfLOInd+1;        end        y1 = cnts(hlfLOInd);        x1 = x(hlfLOInd);        y2 = cnts(hlfLOInd-1);        x2 = x(hlfLOInd-1);        d1 = abs(ratio*maxV - y1);        d2 = abs(ratio*maxV - y2);        xHlf = (x1*d2+x2*d1)/(d1+d2);        wLOut = peak - xHlf;    endend%wLOut = peak - x(hlfLOInd);%disp([wLOut2 wLOut]);%disp([hlfP hlfN hlfHOInd hlfLOInd])
